import type { RefObject } from 'react';
import type { ChildrenWithRef } from '../../types/children-with-ref';
import type { TextFieldProps } from '../TextField';
export interface InlineEditProps extends Omit<TextFieldProps, 'onSubmit' | 'prefix' | 'suffix' | 'size' | 'startAdornment' | 'endAdornment' | 'autoFocus' | 'label' | 'fullWidth' | 'children'> {
    /** Состояние оторажения отображён / скрыт */
    open?: boolean;
    /** Обработчик события клика по кнопке отмены (крестик) */
    onCancel?: () => void;
    /** Обработчик события клика по кнопке подтверждения (галочка) */
    onSubmit?: (value: string | number | readonly string[] | undefined) => void;
    /** ref на компонент, который может служить в качестве указателя вместо дочеренего элемента */
    controlRef?: RefObject<HTMLElement>;
    children?: ChildrenWithRef;
}
